### Smart Contract (Solidity)

```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract UglycashPortfolio is Ownable {
    struct Portfolio {
        uint256 totalValue;
        mapping(address => uint256) tokenBalances;
    }

    mapping(address => Portfolio) public portfolios;

    event PortfolioUpdated(address indexed user, address indexed token, uint256 amount);

    function updatePortfolio(address user, address token, uint256 amount) external onlyOwner {
        require(IERC20(token).balanceOf(user) >= amount, "Insufficient token balance");
        portfolios[user].totalValue += amount;
        portfolios[user].tokenBalances[token] += amount;
        emit PortfolioUpdated(user, token, amount);
    }

    function getUserPortfolio(address user) external view returns (uint256 totalValue, mapping(address => uint256) memory tokenBalances) {
        totalValue = portfolios[user].totalValue;
        tokenBalances = portfolios[user].tokenBalances;
    }
}
```

### Frontend Application (React)

```javascript
import React, { useState, useEffect } from 'react';
import Web3 from 'web3';
import UglycashPortfolio from './UglycashPortfolio.json'; // ABI and address

const web3 = new Web3(window.ethereum);
const contractAddress = '0xYourContractAddress'; // Replace with actual contract address
const contract = new web3.eth.Contract(UglycashPortfolio.abi, contractAddress);

function App() {
    const [account, setAccount] = useState('');
    const [portfolio, setPortfolio] = useState({ totalValue: 0, tokenBalances: {} });

    useEffect(() => {
        const loadWeb3 = async () => {
            if (window.ethereum) {
                window.web3 = new Web3(window.ethereum);
                await window.ethereum.enable();
            } else if (window.web3) {
                window.web3 = new Web3(window.web3.currentProvider);
            } else {
                window.alert('Non-Ethereum browser detected. You should consider trying MetaMask!');
            }
            const accounts = await web3.eth.getAccounts();
            setAccount(accounts[0]);
        };
        loadWeb3();
    }, []);

    useEffect(() => {
        const loadPortfolio = async () => {
            const portfolioData = await contract.methods.getUserPortfolio(account).call();
            setPortfolio(portfolioData);
        };
        if (account) {
            loadPortfolio();
        }
    }, [account]);

    return (
        <div>
            <h1>UGLYCASH Portfolio</h1>
            <p>Connected Account: {account}</p>
            <h2>Portfolio Value: {portfolio.totalValue} USDC</h2>
            <h3>Token Balances:</h3>
            <ul>
                {Object.entries(portfolio.tokenBalances).map(([token, balance]) => (
                    <li key={token}>{token}: {balance} USDC</li>
                ))}
            </ul>
        </div>
    );
}

export default App;
